What does the following program print?

#include<stdio.h>
void f(int *p, int *q)
{
    p = q;
    *p = 2;
}
int i = 0, j = 1;
int main()
{
    f(&i, &j);
    printf("%d %d", i, j);
    return 0;
}

A. 2 2
B. 2 1
C. 0 1
D. 0 2

What is the return value of f(x, c), if the value of x is initialized to 5 before the call? Note that the first parameter is passed by reference, whereas the second parameter is passed by value.

int f(int &x, int c)
{
    c = c - 1;
    if (c == 0) return 1;
    x = x + 1;
    return f(x, c) * x;
}

Consider the following C program.

#include <stdio.h>
void mystery(int *ptra, int *ptrb)
{
    int *temp;
    temp = ptrb;
    ptrb = ptra;
    ptra = temp;
}
int main()
{
    int a = 2016, b = 0, c = 4, d = 42;
    mystery(&a, &b);
    if (a < c)
        b = b + d;
    else
        b = b - d;
    printf("%d\n", b);
    return 0;
}

The output of the program is:

A. -42
B. 0
C. 2016
D. 42

The value printed by the following program is _______.

void f(int *p, int m)
{
    m = m + 5;
    *p = *p + m;
    return;
}
void main()
{
    int i = 5, j = 10;
    f(&i, j);
    printf("%d", i + j);
}
